/**
 * LeetCode算法练习类。
 * <p>
 * 此类包含LeetCode题目的解决方案。
 * 练习算法和数据结构知识。
 *
 * @author zifang
 * @version 1.0
 */
import java.util.ArrayList;

/**
 * _392类。
 */
public class _392 {
    /**
     * isSubsequence方法。
     *      * @param s String类型参数
     * @param t String类型参数
     * @return boolean类型返回值
     */
    public boolean isSubsequence(String s, String t) {
        int tIndex = 0;
        for(int i = 0; i< s.length(); i++){
            // 被比较char
            char c = s.charAt(i);
            boolean continueFlag= false;

            // 长度已经不够比较了就提前返回
            if(t.length() -tIndex < s.length() - i){
                return false;
            }

            // 从上次遍历开始 目标串内是否存在
            for(int j = tIndex; j< t.length(); j++){
                if(c == t.charAt(j)){
                    tIndex = j+1;
                    continueFlag = true;
                    continue;
                }
            }
            if(continueFlag){
                continue;
            }  else {
                return false;
            }
        }
        return true;
    }

    /**
     * main方法。
     *      * @param args String[]类型参数
     * @return static void类型返回值
     */
    public static void main(String[] args) {
        new _392().isSubsequence("leeeeetcode","");


//        r.add(new ArrayList(Arrays.as(){1, 1, 1}));

    }
}
